VALUES
  ('real-estate-moex-02302', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其所有機車1部，寄託於乙處，乙擅自將之以價金新臺幣3萬元讓售給知情的丙，並將該車交付給 丙。下列有關乙丙間法律關係之敘述，何者正確？', '["債權行為有效，物權行為無效", "債權行為無效，物權行為有效", "債權行為效力未定，物權行為無效", "債權行為有效，物權行為效力未定"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02303', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關公同共有之情形，何者不能準用分別共有之規定？', '["公同共有物之分割", "公同共有人應有部分之自由處分", "公同共有物之管理", "公同共有物分割後之權利義務關係"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02304', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙丙3人因繼承而共有祖傳土地1筆，應有部分各為三分之一，以下關於共有之敘述何者正確？', '["3人為維持祖傳土地之完整性，乃訂立禁止永世不得分割之契約，該契約如經登記，即可有效", "甲如欲以該筆土地設定抵押權，只要再得到乙丙其中1人同意即可", "乙欲出賣其應有部分時，應得甲及丙之同意", "即使甲反對，只要乙丙同意時，即可針對該筆共有土地訂立分管契約"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02305', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙丙丁共有土地1筆，應有部分各為四分之一，以下關於分管契約之敘述何者錯誤？', '["分管契約乃約定特定部分之共有物專歸特定共有人使用之契約，故其成立須得全體共有人同意始可", "不動產之分管契約如經登記，可以對抗應有部分之受讓人", "分管契約為債權契約", "分管契約成立後，因情勢變更難以繼續時，任何共有人均得聲請法院以裁定變更之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02306', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', 'XYZ 3人共有土地1筆，各有應有部分三分之一，三人協議分割該筆土地，於6月2日達成協議，8月 20日完成登記。以下敘述何者錯誤？', '["在無法令或約定禁止分割之情形下，任何共有人均得隨時請求分割共有物", "當事人間於6月2日即取得各該分得部分之單獨所有權", "分割共有物之協議屬債權契約", "由於該筆土地面積遼闊，XYZ 3人得約定僅分割其中一半，其餘一半仍繼續共有"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02307', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '以下關於地上權之敘述何者錯誤？', '["地上權可以訂有期限，或為未定期限之地上權", "地上權可以為有償，亦可為無償", "以在他人土地上下之一定空間範圍內設定之地上權稱為區分地上權", "地上權如有支付地租之約定時，地上權人仍可以隨時拋棄其權利"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02308', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '以下關於占有之敘述何者錯誤？', '["寵物店之店員甲照顧顧客乙寄放之寵物狗，帶該隻寵物狗出外散步時，咬傷在公園遊玩之幼童，此時 甲應負損害賠償責任", "動產善意受讓人必須善意且無重大過失始可", "占有人由拍賣或公共市場以善意買得盜贓遺失物時，真正權利人得於2年內，償還支出之價金後，請 求回復其物", "占有人之占有被侵奪者，占有人之返還請求權自侵奪時起，1年間不行使而消滅"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02309', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '以下關於不動產所有權之敘述何者正確？', '["甲於6月15日因其父過世而繼承土地1筆，至10月5日始辦畢繼承登記，則甲於10月5日取得該筆 土地之所有權", "甲於自己所有土地上興建房屋，因與鄰地之境界不明，以致圍牆部分逾越疆界坐落於乙所有鄰地上， 乙雖於興建中即已查知該事，卻待2年後整棟房屋完工後，始請求甲返還土地。此時甲可以拒絕，並 請求以相當價額購買越界部分土地", "區分所有建築物專有部分之所有權人出賣其所有權時，可以保留基地之權利，另為適當之處置", "因土地之讓與或一部分割，而形成袋地時，袋地所有權人僅得通行讓與人或他分割人之所有地，且無 須支付償金"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02310', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '約定於債權已屆清償期而未為清償時，抵押物之所有權移屬於抵押權人者，此一約定之效力為何？', '["非經登記，不得對抗第三人", "非經登記，不生效力", "效力未定", "得撤銷"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02311', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '債務人甲在其3000萬元之抵押土地上，有乙、丙、丁第一、第二及第三順位依次序為1000萬元、2000 萬元及800萬元之普通抵押權，乙為丁抵押權人之利益，而將其第一順位讓與丁。此稱之為：', '["次序之絕對拋棄", "次序之相對拋棄", "次序之讓與", "次序之互易"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
